#include <bits/stdc++.h>
using namespace std;
const int mod=1e5+3;
int n,m,dist[1000006],sum[1000006];
bool use[1000006];
vector<int> g[1000006];
void SPFA(){
	queue<int> b;
	memset(dist,127,sizeof(dist));
	dist[1]=0,b.push(1),sum[1]=1,use[1]=1;
	while(b.size()){
		int u=b.front(),len=g[u].size();
		b.pop();
		use[u]=0;
		for(int i=0;i<len;i++){
			int v=g[u][i];
			if(dist[v]>dist[u]+1){
				dist[v]=dist[u]+1,sum[v]=sum[u],sum[v]%=mod;
				if(!use[v])
					use[v]=1,b.push(v);
			}else if(dist[v]==dist[u]+1)
				sum[v]+=sum[u],sum[v]%=mod;
		}
	}
}
int main(){
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	SPFA();
	for(int i=1;i<=n;i++)
		cout<<sum[i]<<'\n';
	return 0;
}
